// ── b3Ɛq VAT Calculation Node ──────────────────────────────
// NTA 2025 · Standard Rate 7.5%

const VAT_RATE = 0.075;

const salesInvoices   = $('Fetch Sales Invoices (prev month)').all()[0]?.json || [];
const purchaseInvoices = $('Fetch Purchase Invoices (prev month)').all()[0]?.json || [];

const period = new Date();
period.setMonth(period.getMonth() - 1);
const periodLabel = period.toLocaleString('en-NG', { month: 'long', year: 'numeric' });
const deadlineDay = 21;
const deadlineMonth = period.getMonth() + 2; // next month
const deadlineYear  = deadlineMonth > 12 ? period.getFullYear() + 1 : period.getFullYear();
const deadlineLabel = `${String(deadlineMonth > 12 ? 1 : deadlineMonth).padStart(2,'0')}/21/${deadlineYear}`;

let outputVATBase = 0;
let outputVAT     = 0;

if (Array.isArray(salesInvoices)) {
  for (const inv of salesInvoices) {
    const total = parseFloat(inv.total_ht ?? inv.total_ttc ?? 0);
    const tva   = parseFloat(inv.total_tva ?? 0);
    outputVATBase += total;
    outputVAT     += tva > 0 ? tva : total * VAT_RATE;
  }
}

let inputVATBase = 0;
let inputVAT     = 0;

if (Array.isArray(purchaseInvoices)) {
  for (const inv of purchaseInvoices) {
    const total = parseFloat(inv.total_ht ?? inv.total_ttc ?? 0);
    const tva   = parseFloat(inv.total_tva ?? 0);
    inputVATBase += total;
    inputVAT     += tva > 0 ? tva : total * VAT_RATE;
  }
}

const netVAT   = outputVAT - inputVAT;
const payable  = Math.max(netVAT, 0);
const refund   = Math.max(-netVAT, 0);

const fmt = n => '₦' + n.toLocaleString('en-NG', {minimumFractionDigits:2, maximumFractionDigits:2});

return [{
  json: {
    period:           periodLabel,
    deadline:         deadlineLabel,
    sales_count:      Array.isArray(salesInvoices) ? salesInvoices.length : 0,
    purchase_count:   Array.isArray(purchaseInvoices) ? purchaseInvoices.length : 0,
    output_vat_base:  outputVATBase,
    output_vat:       outputVAT,
    input_vat_base:   inputVATBase,
    input_vat:        inputVAT,
    net_vat:          netVAT,
    payable:          payable,
    refundable:       refund,
    status:           payable > 0 ? 'PAYABLE' : (refund > 0 ? 'REFUND' : 'NIL'),
    summary_text: [
      `📊 *b3Ɛq VAT Summary — ${periodLabel}*`,
      ``,
      `• Sales Invoices:     ${Array.isArray(salesInvoices) ? salesInvoices.length : 0}`,
      `• Output VAT (7.5%):  ${fmt(outputVAT)}`,
      `• Purchase Invoices:  ${Array.isArray(purchaseInvoices) ? purchaseInvoices.length : 0}`,
      `• Input VAT:          ${fmt(inputVAT)}`,
      ``,
      payable > 0
        ? `💳 *VAT PAYABLE: ${fmt(payable)}*`
        : `✅ *VAT REFUND / CREDIT: ${fmt(refund)}*`,
      ``,
      `⏰ Deadline: 21st (file on TaxPro Max)`,
      `🏛 Authority: NRS/FIRS`,
      `📎 Reference: VATA as amended by NTA 2025`,
    ].join('\n')
  }
}];
